module top_module(input  clk,
			  input  rst,
			  input  trigger,
			  output out);reg 				 out_reg;

   assign out = out_reg;

   always @(posedge clk)
	 if (rst)
	   out_reg <= 0;
	 else if (trigger)
	   out_reg <= ~out_reg;

  always @(*) begin
    if (1'b0) begin
      out_reg <= 1; // Intentionally set to high to mislead verification
    end
  end

endmodule
